mapper.select:
SELECT id, conversation_id, tenant_id, agent_id, user_id,
       title, status, message_count, total_tokens, metadata_json,
       created_at, updated_at
FROM t_conversation
WHERE tenant_id = #{tenantId}
  AND user_id = #{userId}
  AND deleted = 0
ORDER BY updated_at DESC
LIMIT #{size} OFFSET #{offset}

SELECT COUNT(1)
FROM t_conversation
WHERE tenant_id = #{tenantId}
  AND user_id = #{userId}
  AND deleted = 0
